"use client";

/**
 * 派生アセットのドリルイン詳細パネル。
 *
 * 注: @gunjo/ui には `AssetInspectorPanel` があるが、あれは画像アセット専用
 * （aspect-square のサムネ枠を強制、メタは File name / Dimensions / Size 固定、
 * Rating ☆）。記事・動画・Podcast・SNS連投の系譜には合わないので、より下層の
 * InspectorPanel + InspectorSection + MetadataList + Badge + Timeline を直接
 * 合成している。これらは中立な汎用プリミティブで、ぴったりはまる。
 */

import * as React from "react";
import {
  InspectorPanel,
  InspectorSection,
  MetadataList,
  Badge,
  Button,
  Separator,
  Timeline,
  TimelineItem,
  TimelineTitle,
  TimelineDescription,
  TimelineTime,
  Icon,
} from "@gunjo/ui";
import {
  IconExternalLink,
  IconArrowBackUp,
  IconBan,
} from "@tabler/icons-react";

import {
  type DerivativeAsset,
  STATUS_META,
  FORMAT_LABEL,
  CHANNEL_BY_ID,
  EDITOR_BY_ID,
  SOURCE_BY_ID,
  SYNDICATION_OFFERS,
  PROVISION_META,
  formatDateTime,
} from "./data";
import { StatusBadge } from "./StatusBadge";

export function AssetDetailPanel({
  asset,
  onClose,
}: {
  asset: DerivativeAsset;
  onClose: () => void;
}) {
  const ch = CHANNEL_BY_ID[asset.channel];
  const ed = EDITOR_BY_ID[asset.editorId];
  const offers = SYNDICATION_OFFERS.filter((o) => o.assetId === asset.id);

  const metadata = [
    { label: "フォーマット", value: FORMAT_LABEL[asset.format] },
    { label: "配信チャネル", value: ch.name },
    { label: "担当編集", value: `${ed.name}（${ed.desk}）` },
    {
      label: "公開予定/公開",
      value: formatDateTime(asset.publishAt),
    },
    asset.embargoUntil
      ? {
          label: "エンバーゴ解除",
          value: formatDateTime(asset.embargoUntil),
        }
      : null,
  ].filter(Boolean) as { label: string; value: React.ReactNode }[];

  return (
    <InspectorPanel
      // 既定の固定 w-[320px] h-[420px] を上書きして Sheet 幅にフィットさせる
      className="h-full w-full border-l-0"
      header={
        <div className="flex items-start gap-2 border-b border-border bg-muted/30 px-4 py-3">
          <div className="min-w-0 flex-1 space-y-1">
            <div className="flex flex-wrap items-center gap-2">
              <StatusBadge status={asset.status} />
              <Badge variant="outline">{FORMAT_LABEL[asset.format]}</Badge>
            </div>
            <h3 className="text-sm font-semibold leading-snug text-foreground">
              {asset.title}
            </h3>
          </div>
        </div>
      }
    >
      <InspectorSection title="このアセットについて">
        <p className="text-sm leading-relaxed text-muted-foreground">
          {asset.note}
        </p>
      </InspectorSection>

      <InspectorSection title="メタdata">
        <MetadataList items={metadata} variant="compact" />
      </InspectorSection>

      <Separator />

      <InspectorSection title="源記事（このアセットの出どころ）">
        <Timeline>
          {asset.sourceIds.map((sid, i) => {
            const src = SOURCE_BY_ID[sid];
            return (
              <TimelineItem
                key={sid}
                variant="active"
                connector={i < asset.sourceIds.length - 1}
              >
                <TimelineTitle>{src?.title ?? sid}</TimelineTitle>
                <TimelineTime dateTime={src?.publishedAt}>
                  {src ? `${src.publishedAt} 公開・${src.kicker}` : ""}
                </TimelineTime>
              </TimelineItem>
            );
          })}
        </Timeline>
        {asset.sourceIds.length > 1 ? (
          <p className="text-xs text-muted-foreground">
            複数の源記事が1本に収束（fan-in）したまとめアセット。
          </p>
        ) : null}
      </InspectorSection>

      {offers.length > 0 ? (
        <>
          <Separator />
          <InspectorSection title="外部配信（このアセット）">
            <ul className="space-y-2">
              {offers.map((o) => {
                const pm = PROVISION_META[o.status];
                return (
                  <li
                    key={o.id}
                    className="flex items-center justify-between gap-2 rounded-md border border-border/70 bg-card px-3 py-2"
                  >
                    <div className="min-w-0">
                      <div className="truncate text-sm font-medium text-foreground">
                        {o.partner}
                      </div>
                      <div className="truncate text-xs text-muted-foreground">
                        {o.license}
                      </div>
                    </div>
                    <Badge variant={pm.tone === "muted" ? "outline" : pm.tone}>
                      {pm.label}
                    </Badge>
                  </li>
                );
              })}
            </ul>
          </InspectorSection>
        </>
      ) : null}

      <Separator />

      <InspectorSection title="アクション">
        <div className="grid gap-2">
          <Button variant="default" className="w-full justify-center gap-2">
            <Icon icon={IconExternalLink} size="sm" />
            このアセットを開く
          </Button>
          <Button variant="secondary" className="w-full justify-center gap-2">
            <Icon icon={IconArrowBackUp} size="sm" />
            ワークフローに差し戻す
          </Button>
          {asset.status !== "suspended" ? (
            <Button
              variant="ghost"
              className="w-full justify-center gap-2 text-destructive hover:text-destructive"
            >
              <Icon icon={IconBan} size="sm" />
              配信を停止する
            </Button>
          ) : null}
        </div>
      </InspectorSection>

      <p className="pt-2 text-center text-xs text-muted-foreground">
        現在の状態:{" "}
        <span className="font-medium text-foreground">
          {STATUS_META[asset.status].label}
        </span>
        {" ／ "}
        <button
          type="button"
          onClick={onClose}
          className="underline underline-offset-2 hover:text-foreground"
        >
          閉じる
        </button>
      </p>
    </InspectorPanel>
  );
}

