/** 配信先メディア名の解決（assetId が 源記事 or 派生アセットのどちらでも） */
export function resolveAssetTitle(assetId: string): string {
  return ASSET_BY_ID[assetId]?.title ?? SOURCE_BY_ID[assetId]?.title ?? assetId;
}

/** ISO日時 → 「6/25 09:00」表記 */
export function formatDateTime(iso: string): string {
  const [date, time] = iso.split("T");
  const [, m, d] = date.split("-");
  return time ? `${Number(m)}/${Number(d)} ${time}` : `${Number(m)}/${Number(d)}`;
}

export function formatDate(iso: string): string {
  const [, m, d] = iso.split("-");
  return `${Number(m)}/${Number(d)}`;
}

/** エンバーゴが今日時点で解除前か */
export function isEmbargoed(asset: DerivativeAsset, todayIso = TODAY_ISO): boolean {
  if (!asset.embargoUntil) return false;
  return asset.embargoUntil.slice(0, 10) > todayIso ||
    (asset.embargoUntil.slice(0, 10) === todayIso && asset.status !== "published");
}

import type { LineageEdge, LineageNode } from "@gunjo/ui";
import {
  DERIVATIVE_ASSETS,
  SOURCE_ARTICLES,
  STATUS_META,
  FORMAT_LABEL,
  CHANNEL_BY_ID,
  type AssetStatus,
} from "./data";

/** STATUS tone → LineageGraph node tone（語彙が一致しているのでほぼ素通し） */
const STATUS_TO_LINEAGE_TONE: Record<
  AssetStatus,
  LineageNode["tone"]
> = {
  draft: "muted",
  review: "warning",
  scheduled: "info",
  published: "success",
  suspended: "destructive",
};

/**
 * ドメインデータ → 系譜グラフ（DAG）の nodes / edges へ変換。
 * 源記事を層0、派生アセットを下流の層に置く。まとめ特集は複数の源記事に
 * エッジを張ることで multi-parent（fan-in）になる。
 */
export function buildLineage(): { nodes: LineageNode[]; edges: LineageEdge[] } {
  const nodes: LineageNode[] = [
    ...SOURCE_ARTICLES.map<LineageNode>((s) => ({
      id: s.id,
      label: s.title,
      sublabel: `源記事・${s.publishedAt.slice(5).replace("-", "/")} 公開`,
      tone: "primary",
      ariaLabel: `源記事 ${s.title}`,
    })),
    ...DERIVATIVE_ASSETS.map<LineageNode>((a) => {
      const ch = CHANNEL_BY_ID[a.channel];
      const st = STATUS_META[a.status];
      return {
        id: a.id,
        label: a.title,
        sublabel: `${FORMAT_LABEL[a.format]}・${ch.short}・${st.label}`,
        tone: STATUS_TO_LINEAGE_TONE[a.status],
        ariaLabel: `派生アセット ${a.title}、${ch.name}、状態 ${st.label}`,
      };
    }),
  ];

  const edges: LineageEdge[] = DERIVATIVE_ASSETS.flatMap((a) =>
    a.sourceIds.map((from) => ({ from, to: a.id }))
  );

  return { nodes, edges };
}

