/**
 * 公開予定・エンバーゴ解除のスケジュール。@gunjo/ui の EventCalendar
 * （月×曜日グリッド、role=grid、チップ表示、キーボードナビ）をそのまま使用。
 * 各派生アセットの publishAt をイベント化し、エンバーゴ設定があれば
 * 「🔒 解除」イベントも別チップで載せる。チップ選択で詳細を開く。
 */

import * as React from "react";
import { EventCalendar, type CalendarEvent } from "@gunjo/ui";

import {
  DERIVATIVE_ASSETS,
  STATUS_META,
  FORMAT_LABEL,
  CALENDAR_MONTH,
  TODAY_ISO,
  type DerivativeAsset,
} from "./data";

const STATUS_TO_CAL_TONE: Record<
  DerivativeAsset["status"],
  CalendarEvent["tone"]
> = {
  draft: "muted",
  review: "warning",
  scheduled: "info",
  published: "success",
  suspended: "destructive",
};

export function ScheduleCalendar({
  onSelectAsset,
}: {
  onSelectAsset: (asset: DerivativeAsset) => void;
}) {
  const assetByEventId = React.useMemo(() => {
    const map = new Map<string, DerivativeAsset>();
    for (const a of DERIVATIVE_ASSETS) {
      map.set(`pub-${a.id}`, a);
      if (a.embargoUntil) map.set(`emb-${a.id}`, a);
    }
    return map;
  }, []);

  const events = React.useMemo<CalendarEvent[]>(() => {
    const out: CalendarEvent[] = [];
    for (const a of DERIVATIVE_ASSETS) {
      out.push({
        id: `pub-${a.id}`,
        date: a.publishAt.slice(0, 10),
        label: `${FORMAT_LABEL[a.format]}：${a.title}`,
        tone: STATUS_TO_CAL_TONE[a.status],
        ariaLabel: `${STATUS_META[a.status].label} ${a.title}`,
      });
      if (a.embargoUntil) {
        out.push({
          id: `emb-${a.id}`,
          date: a.embargoUntil.slice(0, 10),
          label: `🔒 エンバーゴ解除：${a.title}`,
          tone: "destructive",
          ariaLabel: `エンバーゴ解除 ${a.title}`,
        });
      }
    }
    return out;
  }, []);

  return (
    <EventCalendar
      month={CALENDAR_MONTH}
      today={TODAY_ISO}
      events={events}
      maxPerDay={4}
      label="公開・エンバーゴ スケジュール 2026年6月"
      weekStartsOn={1}
      weekdayLabels={["日", "月", "火", "水", "木", "金", "土"]}
      onSelectEvent={(ev) => {
        const asset = assetByEventId.get(ev.id);
        if (asset) onSelectAsset(asset);
      }}
    />
  );
}

"use client";

import { Badge } from "@gunjo/ui";
import {
  IconPencil,
  IconEye,
  IconClock,
  IconCircleCheck,
  IconBan,
} from "@tabler/icons-react";

import { STATUS_META, type AssetStatus } from "./data";

/**
 * 状態ピル。Badge の `icon` prop（#276 で「色だけに頼らない status pill」用に
 * 追加されたと JSDoc に明記）をそのまま使い、形（アイコン）＋文字で状態を伝える。
 * Badge の variant 語彙（info/warning/success/destructive）と STATUS_META.tone が
 * 一致しているので、muted だけ outline に落として渡すだけ。
 */
const STATUS_ICON = {
  draft: IconPencil,
  review: IconEye,
  scheduled: IconClock,
  published: IconCircleCheck,
  suspended: IconBan,
} as const;

export function StatusBadge({ status }: { status: AssetStatus }) {
  const meta = STATUS_META[status];
  const Glyph = STATUS_ICON[status];
  const variant = meta.tone === "muted" ? "outline" : meta.tone;
  return (
    <Badge variant={variant} icon={<Glyph />}>
      {meta.label}
    </Badge>
  );
}

"use client";

/**
 * 転載・外部配信の一覧。@gunjo/ui の DataTable（@tanstack/react-table ベース）を
 * そのまま使用。ソート・ページネーション・モバイル renderCard 付き。
 */

import * as React from "react";
import { DataTable, Badge, type ColumnDef } from "@gunjo/ui";

import {
  SYNDICATION_OFFERS,
  PROVISION_META,
  resolveAssetTitle,
  formatDateTime,
  type SyndicationOffer,
} from "./data";

function ProvisionBadge({ status }: { status: SyndicationOffer["status"] }) {
  const pm = PROVISION_META[status];
  return (
    <Badge variant={pm.tone === "muted" ? "outline" : pm.tone}>{pm.label}</Badge>
  );
}

const columns: ColumnDef<SyndicationOffer>[] = [
  {
    accessorKey: "partner",
    header: "配信先メディア",
    cell: ({ row }) => (
      <span className="font-medium text-foreground">{row.original.partner}</span>
    ),
  },
  {
    id: "asset",
    header: "対象コンテンツ",
    accessorFn: (row) => resolveAssetTitle(row.assetId),
    cell: ({ row }) => (
      <span className="block max-w-[28ch] truncate text-muted-foreground">
        {resolveAssetTitle(row.original.assetId)}
      </span>
    ),
  },
  {
    accessorKey: "license",
    header: "ライセンス区分",
    cell: ({ row }) => (
      <span className="block max-w-[24ch] truncate text-muted-foreground">
        {row.original.license}
      </span>
    ),
  },
  {
    accessorKey: "scheduledAt",
    header: "提供/解除予定",
    cell: ({ row }) => (
      <span className="whitespace-nowrap tabular-nums text-muted-foreground">
        {formatDateTime(row.original.scheduledAt)}
      </span>
    ),
  },
  {
    accessorKey: "status",
    header: "提供状態",
    cell: ({ row }) => <ProvisionBadge status={row.original.status} />,
  },
];

export function SyndicationTable() {
  return (
    <DataTable
      columns={columns}
      data={SYNDICATION_OFFERS}
      pageSize={10}
      filter={{ columnId: "partner", placeholder: "配信先で絞り込み…" }}
      labels={{
        filterPlaceholder: "配信先で絞り込み…",
        noResults: "該当する配信先はありません。",
        rowsPerPage: "表示件数",
        paginationSummary: (from, to, total) => `${from}–${to} / 全${total}件`,
        pageSummary: (current, totalPages) => `${current} / ${totalPages}`,
        previous: "前へ",
        next: "次へ",
        firstPage: "最初のページ",
        lastPage: "最後のページ",
      }}
      renderCard={(row) => (
        <div className="space-y-1.5">
          <div className="flex items-center justify-between gap-2">
            <span className="font-medium text-foreground">{row.partner}</span>
            <ProvisionBadge status={row.status} />
          </div>
          <div className="text-sm text-muted-foreground">
            {resolveAssetTitle(row.assetId)}
          </div>
          <div className="text-xs text-muted-foreground">{row.license}</div>
          <div className="text-xs tabular-nums text-muted-foreground">
            {formatDateTime(row.scheduledAt)}
          </div>
        </div>
      )}
    />
  );
}
